import { execution } from '@dynatrace-sdk/automation-utils';
import { EventIngest, EventIngestEventType, eventsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const properties = {
      'audit.action': input.auditAction,
      'audit.target': input.auditTarget,
      'audit.timestamp': new Date().toISOString(),
      'audit.automation': 'true'
    };

    if (input.auditReason) {
      properties['audit.reason'] = input.auditReason;
    }

    if (input.auditDetails) {
      const details = typeof input.auditDetails === 'string' ? JSON.parse(input.auditDetails) : input.auditDetails;
      properties['audit.details'] = JSON.stringify(details);
    }

    if (input.complianceTags) {
      properties['compliance.frameworks'] = input.complianceTags;
    }

    const auditEvent = {
      eventType: EventIngestEventType.CustomInfo,
      title: `Audit: ${input.auditAction} on ${input.auditTarget}`,
      properties: properties
    };

    const result = await eventsClient.createEvent({
      body: auditEvent
    });

    console.log(`Created audit event: ${result.eventIngestResults[0].correlationId}`);

    return {
      auditId: result.eventIngestResults[0].correlationId,
      action: input.auditAction,
      target: input.auditTarget,
      timestamp: new Date().toISOString(),
      complianceFrameworks: input.complianceTags?.split(',') || []
    };
  } catch (error) {
    console.error('Error creating audit event:', error);
    throw new Error(`Failed to create audit event: ${error}`);
  }
}
